print(f"{(a := float(input('Insira o valor de a: '))) and ''}{(b := float(input('Insira o valor de b: '))) and ''}{(c := float(input('Insira o valor de c: '))) and ''}{('Os valores lidos não formam um triângulo.' if a >= b + c or b >= a + c or c >= a + b else ('Triângulo equilátero.' if a == b == c else ('Triângulo isósceles.' if a == b or a == c or b == c else 'Triângulo escaleno.')))}")
